SELECT COUNT(*)
FROM LQ_QUEST_REVIEW
WHERE USER_ID = #{value}

SELECT COUNT(*)
FROM LQ_REWARD_EXCHANGE
WHERE USER_ID = #{value}

SELECT NVL(SUM(USED_POINT), 0)
FROM LQ_REWARD_EXCHANGE
WHERE USER_ID = #{value}

SELECT BADGE_ID
FROM LQ_BADGE
